code.script:
var gr = new GlideRecord('incident');
gr.addQuery('active', true);
gr.query();
while (gr.next()) {
  gs.print(gr.getValue('number') + ' - ' + gr.getValue('short_description'));
}

var gr = new GlideRecord('incident');
gr.addEncodedQuery('active=true^priority=1^sys_created_onRELATIVEGE@hour@ago@24');
gr.orderByDesc('sys_created_on');
gr.query();
while (gr.next()) {
  gs.print(gr.getValue('number') + ' | ' + gr.getDisplayValue('caller_id') + ' | ' + gr.getValue('short_description'));
}

var ga = new GlideAggregate('incident');
ga.addQuery('active', true);
ga.groupBy('assignment_group');
ga.addAggregate('COUNT');
ga.query();

while (ga.next()) {
  gs.print(ga.getDisplayValue('assignment_group') + ' - ' + ga.getAggregate('COUNT'));
}

var gr = new GlideRecord('incident');
gr.addQuery('state', 6); // Resolved
gr.addEncodedQuery('resolved_atRELATIVELE@dayofweek@ago@7');
gr.query();

while (gr.next()) {
  gr.state = 7; // Closed
  gr.close_notes = 'Auto-closed after 7 days in Resolved state.';
  gr.update();
}

answer = false;

if (gs.hasRole('sn_sensitive_incident.reader')) {
  answer = true;
} else if (!current.assignment_group.nil()) {
  var gm = new GlideRecord('sys_user_grmember');
  gm.addQuery('group', current.assignment_group);
  gm.addQuery('user', gs.getUserID());
  gm.query();
  answer = gm.hasNext();
}

var count = 0;
var gr = new GlideRecord('sys_user');
gr.addQuery('active', true);
gr.addQuery('u_disable_account', true);
gr.query();

while (gr.next()) {
  gr.active = false;
  gr.update();
  count++;
}

gs.print('Users deactivated: ' + count);

var ciSysId = 'PUT_CI_SYS_ID_HERE';
var rel = new GlideRecord('cmdb_rel_ci');
rel.addQuery('parent', ciSysId).addOrCondition('child', ciSysId);
rel.query();

while (rel.next()) {
  gs.print(rel.getDisplayValue('parent') + ' -- ' + rel.getDisplayValue('type') + ' --> ' + rel.getDisplayValue('child'));
}

var gr = new GlideRecord('incident');
gr.addEncodedQuery('active=false^sys_updated_onRELATIVELE@dayofweek@ago@90');
gr.query();

while (gr.next()) {
  gr.setWorkflow(false);
  gr.u_archive_candidate = true;
  gr.update();
}
